from itertools import permutations

def late_clock(digits):
    best = -1
    best_h = best_m = 0
    for a, b, c, d in permutations(digits, 4):
        h = a * 10 + b
        m = c * 10 + d
        if 0 <= h <= 23 and 0 <= m <= 59:
            total = h * 60 + m
            if total > best:
                best = total
                best_h, best_m = h, m
    return f"{best_h:02d}:{best_m:02d}"

def decode(message):
    a = ord('a')
    z = ord('z')
    out = []
    for c in message:
        if c == ' ':
            out.append(' ')
        else:
            out.append(chr(a + z - ord(c)))
    return ''.join(out)

