def main():
    data = sys.stdin.buffer.read().splitlines()
    if not data:
        return
    l = int(data[0])
    CAP = 1 << 32
    stack = [1]
    x = 0
    for i in range(1, l + 1):
        line = data[i].decode().strip()
        if line == "add":
            x += stack[-1]
            if x >= CAP:
                sys.stdout.write("OVERFLOW!!!")
                return
        elif line == "end":
            if len(stack) > 1:
                stack.pop()
        else:
            # for n
            n = int(line.split()[1])
            mul = stack[-1] * n
            if mul >= CAP:
                mul = CAP
            stack.append(mul)
    sys.stdout.write(str(x))

