import sys

MOD = 1000000007

def modinv(a):
    return pow(a, MOD - 2, MOD)

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    k = int(data[0])
    c = list(map(int, data[1:1+k]))
    n = sum(c)
    fact = [1] * (n + 1)
    for i in range(1, n + 1):
        fact[i] = fact[i-1] * i % MOD
    invfact = [1] * (n + 1)
    invfact[n] = modinv(fact[n])
    for i in range(n, 0, -1):
        invfact[i-1] = invfact[i] * i % MOD

    def comb(N, R):
        if R < 0 or R > N:
            return 0
        return fact[N] * invfact[R] % MOD * invfact[N-R] % MOD

    ways = 1
    S = c[0]
    for i in range(1, k):
        ci = c[i]
        ways = ways * comb(S + ci - 1, ci - 1) % MOD
        S += ci
    sys.stdout.write(str(ways))

if __name__ == "__main__":
    main()

