import sys

N = 10
V = N * N

def idx(r, c):
    return r * N + c

def build_matrix_rows():
    rows = [0] * V
    for r in range(N):
        for c in range(N):
            i = idx(r, c)
            mask = 0
            for dr, dc in ((0,0), (-1,0), (1,0), (0,-1), (0,1)):
                rr, cc = r + dr, c + dc
                if 0 <= rr < N and 0 <= cc < N:
                    mask ^= 1 << idx(rr, cc)
            rows[i] = mask
    return rows

A_rows = build_matrix_rows()

def solve_gf2(A, b):
    # A: list of int bitmasks length V, each V bits
    # b: int bitmask length V
    rows = [A[i] | (((b >> i) & 1) << V) for i in range(V)]  # augmented column at bit V
    where = [-1] * V
    r = 0
    for col in range(V):
        pivot = -1
        for i in range(r, V):
            if (rows[i] >> col) & 1:
                pivot = i
                break
        if pivot == -1:
            continue
        rows[r], rows[pivot] = rows[pivot], rows[r]
        where[col] = r
        pivrow = rows[r]
        for i in range(V):
            if i != r and ((rows[i] >> col) & 1):
                rows[i] ^= pivrow
        r += 1
        if r == V:
            break

    # Unique solution guaranteed; extract
    x = 0
    for col in range(V):
        rr = where[col]
        if rr != -1:
            val = (rows[rr] >> V) & 1
            if val:
                x |= 1 << col
    return x

