import sys

def solve_case(a, b, c):
    types = list(range(1, 8))  # bit 0:A, 1:B, 2:C
    best = 0
    for mask in range(1 << 7):
        cnt = mask.bit_count()
        if cnt <= best:
            continue
        ra = rb = rc = 0
        for i in range(7):
            if (mask >> i) & 1:
                t = types[i]
                ra += (t & 1) != 0
                rb += (t & 2) != 0
                rc += (t & 4) != 0
                if ra > a or rb > b or rc > c:
                    break
        else:
            best = cnt
    return best

