import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    n = int(data[0])

    FULL = 0b111

    # Precompute transitions for each cur_mask: list of next_mask counts
    trans = [None] * 8

    for start_mask in range(8):
        counts = {}

        def dfs(cur_mask, next_mask):
            if cur_mask == FULL:
                counts[next_mask] = counts.get(next_mask, 0) + 1
                return
            # find first empty row in current column
            for r in range(3):
                if not (cur_mask & (1 << r)):
                    break
            # try place L-tromino covering (r,0)
            for t in (r - 1, r):
                if t < 0 or t > 1:
                    continue
                cells = [(t, 0), (t + 1, 0), (t, 1), (t + 1, 1)]
                for miss in range(4):
                    if cells[miss] == (r, 0):
                        continue
                    ok = True
                    cm = cur_mask
                    nm = next_mask
                    for i, (rr, cc) in enumerate(cells):
                        if i == miss:
                            continue
                        if cc == 0:
                            bit = 1 << rr
                            if cm & bit:
                                ok = False
                                break
                            cm |= bit
                        else:
                            bit = 1 << rr
                            if nm & bit:
                                ok = False
                                break
                            nm |= bit
                    if ok:
                        dfs(cm, nm)

        dfs(start_mask, 0)
        trans[start_mask] = list(counts.items())

    dp = [0] * 8
    dp[0] = 1
    for _ in range(n):
        ndp = [0] * 8
        for mask in range(8):
            val = dp[mask]
            if not val:
                continue
            for nm, cnt in trans[mask]:
                ndp[nm] += val * cnt
        dp = ndp

    sys.stdout.write(str(dp[0]))

if __name__ == "__main__":
    solve()

