    p = data[3:3+n]

    pref = [0]*(n+1)
    for i in range(1, n+1):
        pref[i] = pref[i-1] + p[i-1]

    w = [0]*(n+1)  # w[i] valid for i>=m: sum of length m ending at i
    for i in range(m, n+1):
        w[i] = pref[i] - pref[i-m]

    NEG = -10**30

    dp_prev = [0]*(n+1)  # for j=0
    for j in range(1, k+1):
        dp_cur = [NEG]*(n+1)
        # dp_cur[i] = max(dp_cur[i-1], dp_prev[i-m] + w[i]) for i>=m
        # For i < j*m, impossible to place j segments
        for i in range(1, n+1):
            best = dp_cur[i-1]
            if i >= m:
                cand = dp_prev[i-m] + w[i]
                if cand > best:
                    best = cand
            dp_cur[i] = best
        dp_prev = dp_cur

