import sys

def solve():
    data = sys.stdin.read().splitlines()
    if not data:
        return
    W = int(data[0].strip())
    words = [line.strip() for line in data[1:1+W]]

    present = set()
    for w in words:
        present.update(w)
    letters = sorted(present)
    n = len(letters)
    idx = {ch:i for i,ch in enumerate(letters)}

    # adjacency matrix for direct constraints: u < v
    adj = [[False]*n for _ in range(n)]

    for i in range(W-1):
        w1, w2 = words[i], words[i+1]
        m = min(len(w1), len(w2))
        j = 0
        while j < m and w1[j] == w2[j]:
            j += 1
        if j < m:
            a, b = w1[j], w2[j]
            if a != b:
                adj[idx[a]][idx[b]] = True
        else:
            # If one is prefix of other, no new info needed (and conflicts assumed absent)
            pass

    # transitive closure (Floyd-Warshall)
    reach = [row[:] for row in adj]
    for k in range(n):
        rk = reach[k]
        for i in range(n):
            if reach[i][k]:
                ri = reach[i]
                for j in range(n):
                    if rk[j] and not ri[j]:
                        ri[j] = True

    # Build signatures: (lower_set, upper_set) as bitmasks
    lowers = [0]*n
    uppers = [0]*n
    for i in range(n):
        low = 0
        up = 0
        for j in range(n):
            if reach[j][i]:
                low |= 1 << j
            if reach[i][j]:
                up |= 1 << j
        lowers[i] = low
        uppers[i] = up

    sig_to_class = {}
    class_members = []
    class_of = [-1]*n
    for i in range(n):
        sig = (lowers[i], uppers[i])
        if sig not in sig_to_class:
            sig_to_class[sig] = len(class_members)
            class_members.append([])
        c = sig_to_class[sig]
        class_members[c].append(letters[i])
        class_of[i] = c

    C = len(class_members)
    # sort members within class by normal order
    for c in range(C):
        class_members[c].sort()

    # Build class DAG using reachability between any members (signatures ensure consistency)
    class_adj = [set() for _ in range(C)]
    indeg = [0]*C
    for i in range(n):
        ci = class_of[i]
        ri = reach[i]
        for j in range(n):
            if ri[j]:
                cj = class_of[j]
                if ci != cj and cj not in class_adj[ci]:
                    class_adj[ci].add(cj)

    for u in range(C):
        for v in class_adj[u]:
            indeg[v] += 1

    # Kahn's algorithm; tie-break by smallest letter in class (normal order) for determinism
    import heapq
    heap = []
    for c in range(C):
        if indeg[c] == 0:
            heapq.heappush(heap, (class_members[c][0], c))

    order = []
    while heap:
        _, u = heapq.heappop(heap)
        order.append(u)
        for v in class_adj[u]:
            indeg[v] -= 1
            if indeg[v] == 0:
                heapq.heappush(heap, (class_members[v][0], v))

    # Output each class on new line as concatenated letters
    out_lines = [''.join(class_members[c]) for c in order]
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

