import sys

def solve(data: str):
    it = iter(data.strip().splitlines())
    out_lines = []
    for line in it:
        line = line.strip()
        if not line:
            continue
        n = int(line)
        if n == 0:
            break
        avail = [[] for _ in range(31)]
        for i in range(n):
            parts = list(map(int, next(it).split()))
            f = parts[0]
            for d in parts[1:1+f]:
                if 1 <= d <= 30:
                    avail[d].append(i)
        hold = [(1 << i) for i in range(n)]
        allbits = (1 << n) - 1
        ans = -1
        for d in range(1, 31):
            if avail[d]:
                u = 0
                for i in avail[d]:
                    u |= hold[i]
                for i in avail[d]:
                    hold[i] = u
            # check after day d
            if any(h == allbits for h in hold):
                ans = d
                break
        out_lines.append(str(ans))
    return "\n".join(out_lines)

