import sys, math

def v_factor(n, p):
    c = 0
    while n % p == 0:
        n //= p
        c += 1
    return c

def parse_scaled_1e9(s):
    s = s.strip()
    if '.' in s:
        a, b = s.split('.', 1)
        b = (b + '0' * 9)[:9]
    else:
        a, b = s, '0' * 9
    return int(a) * 10**9 + int(b)

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    n = int(data[0])
    denom = 10**9
    freq = {}
    for i in range(1, n + 1):
        x = parse_scaled_1e9(data[i])
        g = math.gcd(x, denom)
        p = x // g
        q = denom // g
        e2 = v_factor(p, 2) - v_factor(q, 2)
        e5 = v_factor(p, 5) - v_factor(q, 5)
        key = (e2, e5)
        freq[key] = freq.get(key, 0) + 1

    keys = list(freq.keys())
    ans = 0
    for i, k1 in enumerate(keys):
        c1 = freq[k1]
        e21, e51 = k1
        for j in range(i, len(keys)):
            k2 = keys[j]
            e22, e52 = k2
            if e21 + e22 >= 0 and e51 + e52 >= 0:
                c2 = freq[k2]
                if i == j:
                    ans += c1 * (c1 - 1) // 2
                else:
                    ans += c1 * c2
    sys.stdout.write(str(ans))

if __name__ == "__main__":
    main()

