import sys, bisect

class SegTree:
    __slots__ = ("n", "mx", "lz")
    def __init__(self, arr):
        n = 1
        while n < len(arr):
            n <<= 1
        self.n = n
        self.mx = [-10**30] * (2 * n)
        self.lz = [0] * (2 * n)
        for i, v in enumerate(arr):
            self.mx[n + i] = v
        for i in range(n - 1, 0, -1):
            self.mx[i] = self.mx[i << 1] if self.mx[i << 1] > self.mx[i << 1 | 1] else self.mx[i << 1 | 1]

    def _apply(self, idx, val):
        self.mx[idx] += val
        self.lz[idx] += val

    def _push(self, idx):
        lz = self.lz[idx]
        if lz:
            self._apply(idx << 1, lz)
            self._apply(idx << 1 | 1, lz)
            self.lz[idx] = 0

    def add(self, l, r, val):
        if l > r:
            return
        def rec(idx, nl, nr):
            if l <= nl and nr <= r:
                self._apply(idx, val)
                return
            self._push(idx)
            mid = (nl + nr) >> 1
            if l <= mid:
                rec(idx << 1, nl, mid)
            if r > mid:
                rec(idx << 1 | 1, mid + 1, nr)
            self.mx[idx] = self.mx[idx << 1] if self.mx[idx << 1] > self.mx[idx << 1 | 1] else self.mx[idx << 1 | 1]
        rec(1, 0, self.n - 1)

    def max_all(self):
        return self.mx[1]

def main():
    data = sys.stdin.buffer.read().split()
    if not data:
        return
    it = iter(data)
    n = int(next(it)); m = int(next(it)); p = int(next(it))
    weapons = []
    for _ in range(n):
        a = int(next(it)); ca = int(next(it))
        weapons.append((a, ca))
    armors = []
    for _ in range(m):
        b = int(next(it)); cb = int(next(it))
        armors.append((b, cb))
    monsters = []
    for _ in range(p):
        x = int(next(it)); y = int(next(it)); z = int(next(it))
        monsters.append((x, y, z))

    weapons.sort()
    armors.sort()
    monsters.sort()

    b_vals = [b for b, _ in armors]
    base = [-cb for _, cb in armors]
    seg = SegTree(base)

    ans = -10**30
    mi = 0
    for a, ca in weapons:
        while mi < p and monsters[mi][0] < a:
            _, y, z = monsters[mi]
            idx = bisect.bisect_right(b_vals, y)
            if idx < m:
                seg.add(idx, m - 1, z)
            mi += 1
        cur = seg.max_all() - ca
        if cur > ans:
            ans = cur

    sys.stdout.write(str(ans))

