import sys

MP = 999983

def build_prefix_prime_counts(limit):
    n = limit
    is_prime = bytearray(b"\x01") * (n + 1)
    if n >= 0:
        is_prime[0] = 0
    if n >= 1:
        is_prime[1] = 0
    import math
    r = int(math.isqrt(n))
    for i in range(2, r + 1):
        if is_prime[i]:
            step = i
            start = i * i
            is_prime[start:n+1:step] = b"\x00" * (((n - start) // step) + 1)
    pref = [0] * (n + 1)
    c = 0
    for i in range(n + 1):
        if is_prime[i]:
            c += 1
        pref[i] = c
    return pref

PREF = build_prefix_prime_counts(MP)

def count_primes_in_range(a, b):
    if b < 2 or a > b:
        return 0
    if a < 2:
        a = 2
    if b > MP:
        b = MP
    if a > b:
        return 0
    return PREF[b] - (PREF[a - 1] if a > 0 else 0)

def main():
    data = sys.stdin.buffer.read()
    if not data:
        return
    nums = []
    num = 0
    in_num = False
    for ch in data:
        if 48 <= ch <= 57:
            num = num * 10 + (ch - 48)
            in_num = True
        else:
            if in_num:
                nums.append(num)
                num = 0
                in_num = False
    if in_num:
        nums.append(num)

    out_lines = []
    i = 0
    L = len(nums)
    while i < L:
        n = nums[i]
        i += 1
        if n == 0:
            break
        total = 0
        # n pairs follow
        end = i + 2 * n
        while i < end:
            p = nums[i]; m = nums[i + 1]
            i += 2
            a = p - m
            b = p + m
            if a < 2:
                a = 2
            if b > MP:
                b = MP
            if a <= b:
                x = PREF[b] - PREF[a - 1]
                if x > 1:
                    total += (x - 1)
            # else x=0
        out_lines.append(str(total))
    sys.stdout.write("\n".join(out_lines))

