import sys, math

def sieve(limit: int):
    is_prime = bytearray(b"\x01") * (limit + 1)
    if limit >= 0:
        is_prime[0] = 0
    if limit >= 1:
        is_prime[1] = 0
    m = int(limit ** 0.5)
    for i in range(2, m + 1):
        if is_prime[i]:
            step = i
            start = i * i
            is_prime[start:limit + 1:step] = b"\x00" * (((limit - start) // step) + 1)
    return is_prime

