import sys, heapq

def construct(n, d):
    D = sum(d)
    if D == 0:
        return []
    if D == 1:
        return None
    if n == 2:
        if d[0] != d[1]:
            return None
        t = d[0]
        if t > 10000:
            return None
        line = "11"
        return [line] * t

    mx = max(d)
    if mx * 2 > D:
        return None

    heap = []
    for i, x in enumerate(d):
        if x > 0:
            heapq.heappush(heap, (-x, i))

    matches = []
    max_party = min(5, n)

    while heap:
        if len(heap) == 1:
            return None
        take = min(max_party, len(heap))
        picked = []
        for _ in range(take):
            negx, idx = heapq.heappop(heap)
            picked.append([idx, -negx])
        # ensure at least 2
        if len(picked) < 2:
            return None

        # apply one decrement to all picked
        bits = ['0'] * n
        for idx, _ in picked:
            bits[idx] = '1'
        matches.append(''.join(bits))
        if len(matches) > 10000:
            return None

        for idx, x in picked:
            x -= 1
            if x > 0:
                heapq.heappush(heap, (-x, idx))

    return matches

