import sys

MOD = 1000000007

def build_pi(p):
    m = len(p)
    pi = [0]*m
    j = 0
    for i in range(1, m):
        while j > 0 and p[i] != p[j]:
            j = pi[j-1]
        if p[i] == p[j]:
            j += 1
            pi[i] = j
    return pi

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    n = int(data[0])
    s = data[1].strip()
    m = len(s)
    if m > 2*n:
        print(0)
        return

    pi = build_pi(s)

    # automaton for states 0..m-1 (matched prefix length), transitions for '(' and ')'
    trans = [[0,0] for _ in range(m)]
    hit = [[0,0] for _ in range(m)]
    chars = ['(', ')']
    for k in range(m):
        for ci, ch in enumerate(chars):
            j = k
            while j > 0 and s[j] != ch:
                j = pi[j-1]
            if s[j] == ch:
                j += 1
            if j == m:
                hit[k][ci] = 1
                j = pi[m-1]
            trans[k][ci] = j

    # dp[bal][k][f]
    dp0 = [[[0]*2 for _ in range(m)] for __ in range(n+1)]
    dp0[0][0][0] = 1

    for pos in range(2*n):
        dp1 = [[[0]*2 for _ in range(m)] for __ in range(n+1)]
        rem = 2*n - pos
        for bal in range(n+1):
            # prune impossible balances
            if bal > rem:
                continue
            row = dp0[bal]
            for k in range(m):
                a0 = row[k][0]
                a1 = row[k][1]
                if a0==0 and a1==0:
                    continue
                # add '('
                if bal + 1 <= n:
                    nk = trans[k][0]
                    h = hit[k][0]
                    if a0:
                        dp1[bal+1][nk][0 if h==0 else 1] = (dp1[bal+1][nk][0 if h==0 else 1] + a0) % MOD
                    if a1:
                        dp1[bal+1][nk][1] = (dp1[bal+1][nk][1] + a1) % MOD
                # add ')'
                if bal > 0:
                    nk = trans[k][1]
                    h = hit[k][1]
                    if a0:
                        dp1[bal-1][nk][0 if h==0 else 1] = (dp1[bal-1][nk][0 if h==0 else 1] + a0) % MOD
                    if a1:
                        dp1[bal-1][nk][1] = (dp1[bal-1][nk][1] + a1) % MOD
        dp0 = dp1

    ans = 0
    for k in range(m):
        ans = (ans + dp0[0][k][1]) % MOD
    print(ans)

