import sys
from functools import lru_cache

def count_rect(A, B):
    if A < 0 or B < 0:
        return 0
    # ensure within 0..1e9 but can be up to 2^30; use 31 bits (0..30) plus maybe bit 30 for 1e9 < 2^30
    maxbit = max(A.bit_length(), B.bit_length(), 1) - 1
    # process from maxbit down to 0
    @lru_cache(None)
    def dp(bit, ta, tb):
        if bit < 0:
            return 1
        limA = (A >> bit) & 1 if ta else 1
        limB = (B >> bit) & 1 if tb else 1
        res = 0
        # (0,0)
        if 0 <= limA and 0 <= limB:
            res += dp(bit-1, ta and (0 == limA), tb and (0 == limB))
        # (0,1)
        if 0 <= limA and 1 <= limB:
            res += dp(bit-1, ta and (0 == limA), tb and (1 == limB))
        # (1,0)
        if 1 <= limA and 0 <= limB:
            res += dp(bit-1, ta and (1 == limA), tb and (0 == limB))
        return res

    return dp(maxbit, True, True)

