def largest_histogram_area(heights):
    stack = []
    max_area = 0
    n = len(heights)
    for i in range(n + 1):
        h = heights[i] if i < n else 0
        while stack and heights[stack[-1]] > h:
            top = stack.pop()
            height = heights[top]
            left = stack[-1] + 1 if stack else 0
            width = i - left
            area = height * width
            if area > max_area:
                max_area = area
        stack.append(i)
    return max_area

