import sys

def solve():
    data = sys.stdin.read().strip().splitlines()
    if not data:
        return
    n, m, k = map(int, data[0].split())
    dir_line = data[1].strip()
    s = data[2].strip()
    T = len(s)
    init_dir = -1 if dir_line == "to head" else 1

    def ctrl_move(c, d):
        c2 = c + d
        d2 = d
        if c2 == 1 or c2 == n:
            d2 = -d2
        return c2, d2

    # dp_next[s_pos][c_pos][dir_index] -> best outcome from start of minute t+1
    # outcome: T+1 means stowaway escapes; else minute number when caught
    dp_next = [[[T + 1 for _ in range(2)] for _ in range(n + 1)] for _ in range(n + 1)]
    dp_cur = [[[T + 1 for _ in range(2)] for _ in range(n + 1)] for _ in range(n + 1)]

    # For terminal minute T (always idle): stowaway leaves and wins unless already caught earlier.
    # So dp at start of minute T is escape for all s!=c.
    # dp_next currently represents dp at start of minute T+1 (beyond end), unused but set to escape.
    # We'll compute dp for t=T down to 1, keeping dp_next as dp[t+1].
    # Initialize dp_next as dp[T+1] = escape.
    for t in range(T, 0, -1):
        state = s[t - 1]
        for sp in range(1, n + 1):
            for cp in range(1, n + 1):
                for di in range(2):
                    d = -1 if di == 0 else 1
                    if sp == cp:
                        # would have been caught at end of previous minute
                        dp_cur[sp][cp][di] = t - 1
                        continue
                    if t == T:
                        # terminal station minute: stowaway leaves and wins
                        dp_cur[sp][cp][di] = T + 1
                        continue

                    c2, d2 = ctrl_move(cp, d)
                    di2 = 0 if d2 == -1 else 1

                    best = -1
                    if state == '0':  # moving: stow moves then controller
                        for ns in (sp - 1, sp, sp + 1):
                            if ns < 1 or ns > n:
                                continue
                            if ns == cp:
                                # caught immediately at minute t
                                outcome = t
                            else:
                                if ns == c2:
                                    outcome = t
                                else:
                                    outcome = dp_next[ns][c2][di2]
                            if outcome > best:
                                best = outcome
                    else:  # idle: stow leaves, controller moves, stow enters any wagon
                        # stow can choose any wagon; if chooses c2 -> caught at minute t
                        # he will avoid if possible
                        for ns in range(1, n + 1):
                            if ns == c2:
                                outcome = t
                            else:
                                outcome = dp_next[ns][c2][di2]
                            if outcome > best:
                                best = outcome

                    dp_cur[sp][cp][di] = best

        dp_next, dp_cur = dp_cur, dp_next

    init_di = 0 if init_dir == -1 else 1
    res = dp_next[m][k][init_di]
    out = []
    if res == T + 1:
        out.append("Stowaway")
    else:
        out.append(f"Controller {res}")
    sys.stdout.write("\n".join(out))

