            n //= 2

    # Factor 3
    if n % 3 == 0:
        if spf is None:
            spf = 3
        lpf = 3
        while n % 3 == 0:
            n //= 3

    # 6k ± 1 trial division
    i = 5
    step = 2
    while i * i <= n:
        if n % i == 0:
            if spf is None:
                spf = i
            lpf = i
            while n % i == 0:
                n //= i
        i += step
        step = 6 - step  # alternates 2,4

    if n > 1:
        if spf is None:
            # original is prime
            return []
        lpf = n

    if spf is None:
        return []

    return [int(lpf), int(original // spf)]

