import sys

def solve_case(n, p):
    half = n // 2
    if half < 3:
        return (0, 0, 0)

    groups = []
    i = 0
    while i < n:
        j = i + 1
        while j < n and p[j] == p[i]:
            j += 1
        groups.append(j - i)
        i = j

    if len(groups) < 3:
        return (0, 0, 0)

    g = groups[0]
    if g == 0:
        return (0, 0, 0)

    s = 0
    idx = 1
    while idx < len(groups) and s <= g:
        s += groups[idx]
        idx += 1
    if s <= g:
        return (0, 0, 0)

    b = 0
    best = (0, 0, 0)
    total = g + s
    while idx < len(groups) and total < half:
        b += groups[idx]
        total += groups[idx]
        idx += 1
        if total > half:
            b -= (total - half)
            total = half
        if b > g and total <= half:
            best = (g, s, b)
        if total == half:
            break

    return best if best != (0, 0, 0) else (0, 0, 0)

