if __name__ == "__main__":
    main()

import re

def filter_words(phrase):
    if phrase is None:
        return ""
    s = str(phrase).strip()
    if not s:
        return ""
    s = re.sub(r"\s+", " ", s).lower()
    return s[0].upper() + s[1:]

import sys
from collections import deque

def bfs(starts, rev, n):
    dist = [-1] * (n + 1)
    q = deque()
    for s in starts:
        dist[s] = 0
        q.append(s)
    while q:
        v = q.popleft()
        dv = dist[v] + 1
        for u in rev[v]:
            if dist[u] == -1:
                dist[u] = dv
                q.append(u)
    return dist

def main():
    data = sys.stdin.buffer.read().split()
    if not data:
        return
    n = int(data[0])
    a = [0] + list(map(int, data[1:1+n]))

    rev = [[] for _ in range(n + 1)]
    for i in range(1, n + 1):
        step = a[i]
        j = i - step
        if j >= 1:
            rev[j].append(i)
        j = i + step
        if j <= n:
            rev[j].append(i)

    evens = [i for i in range(1, n + 1) if (a[i] & 1) == 0]
    odds = [i for i in range(1, n + 1) if (a[i] & 1) == 1]

    dist_to_even = bfs(evens, rev, n)
    dist_to_odd = bfs(odds, rev, n)

    out = []
    for i in range(1, n + 1):
        if a[i] & 1:
            out.append(str(dist_to_even[i]))
        else:
            out.append(str(dist_to_odd[i]))
    sys.stdout.write(" ".join(out))

if __name__ == "__main__":
    main()

import sys

sys.setrecursionlimit(3000000)

def solve():
    data = list(map(int, sys.stdin.buffer.read().split()))
    if not data:
        return
    n = data[0]
    p = data[1:]
    children = [[] for _ in range(n + 1)]
    for i in range(2, n + 1):
        parent = p[i - 2]
        children[parent].append(i)

    sets = [None] * (n + 1)
    offs = [0] * (n + 1)

    def dfs(v):
        if not children[v]:
            s = set()
            off = 0
            # toggle exponent 0
            s.add(0)
            sets[v] = s
            offs[v] = off
            return

        # process children
        for c in children[v]:
            dfs(c)

        # choose largest child as base
        base = children[v][0]
        for c in children[v][1:]:
            if len(sets[c]) > len(sets[base]):
                base = c

        s = sets[base]
        off = offs[base]

        # merge other children via XOR (symmetric difference)
        for c in children[v]:
            if c == base:
                continue
            sc = sets[c]
            oc = offs[c]
            delta = oc - off
            if delta == 0:
                # direct symmetric difference
                for e in sc:
                    if e in s:
                        s.remove(e)
                    else:
                        s.add(e)
            else:
                for e in sc:
                    val = e + delta
                    if val in s:
                        s.remove(val)
                    else:
                        s.add(val)

        # shift by +1 (multiply by x)
        off += 1

        # add constant 1 (toggle exponent 0)
        key0 = -off
        if key0 in s:
            s.remove(key0)
        else:
            s.add(key0)

        sets[v] = s
        offs[v] = off

    dfs(1)
    out = str(len(sets[1]))
    sys.stdout.write(out)

if __name__ == "__main__":
    solve()

def ranks(a):
    vals = sorted(set(a), reverse=True)
    rank_map = {v: i + 1 for i, v in enumerate(vals)}
    return [rank_map[x] for x in a]
